import{_ as t,o as a,c as o,a0 as n}from"./chunks/framework.DoRPXVp_.js";const u=JSON.parse('{"title":"Channels","description":"","frontmatter":{},"headers":[],"relativePath":"guide/channels.md","filePath":"guide/channels.md"}'),r={name:"guide/channels.md"};function d(s,e,l,i,c,h){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="channels" tabindex="-1">Channels <a class="header-anchor" href="#channels" aria-label="Permalink to &quot;Channels&quot;">​</a></h1><p>Sidebar → <strong>Channels</strong> → New</p><p>Select the type and fill in the credentials, then assign agent + saver + memory. Every user/group chat is isolated automatically.</p><h2 id="supported-channels" tabindex="-1">Supported Channels <a class="header-anchor" href="#supported-channels" aria-label="Permalink to &quot;Supported Channels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Required fields</th></tr></thead><tbody><tr><td>Lark / Feishu</td><td>App ID, App Secret</td></tr><tr><td>Slack</td><td>Bot Token (<code>xoxb-...</code>), App Token (<code>xapp-...</code>)</td></tr><tr><td>WeCom</td><td>Bot ID, Secret</td></tr><tr><td>WeChat</td><td>QR code login (credentials auto-populated)</td></tr></tbody></table><h2 id="lark-feishu-setup" tabindex="-1">Lark / Feishu Setup <a class="header-anchor" href="#lark-feishu-setup" aria-label="Permalink to &quot;Lark / Feishu Setup&quot;">​</a></h2><ol><li>Create a bot app in the <a href="https://open.feishu.cn" target="_blank" rel="noreferrer">Feishu Developer Console</a></li><li>Enable <strong>Bot</strong> capability</li><li>Grant required permissions:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Description</th></tr></thead><tbody><tr><td><code>im:message:send_as_bot</code></td><td>Send messages as bot</td></tr><tr><td><code>im:message.p2p_msg:readonly</code></td><td>Receive direct messages</td></tr><tr><td><code>im:message.group_at_msg:readonly</code></td><td>Receive group @bot messages</td></tr><tr><td><code>im:message.group_msg</code></td><td>Receive all group messages</td></tr><tr><td><code>im:message:readonly</code></td><td>Read message content</td></tr><tr><td><code>im:chat:readonly</code></td><td>Read chat/group info</td></tr><tr><td><code>im:resource</code></td><td>Read files and images in messages</td></tr><tr><td><code>contact:user.base:readonly</code></td><td>Read basic user info</td></tr><tr><td><code>contact:contact.base:readonly</code></td><td>Read basic contact info</td></tr></tbody></table><ol start="4"><li>Under <strong>Events &amp; Callbacks</strong>, set the subscription mode to <strong>Long Connection</strong></li><li>In Web UI → <strong>Channels</strong>, create a Lark channel and fill in <strong>App ID</strong> and <strong>App Secret</strong></li></ol><h2 id="wecom-setup" tabindex="-1">WeCom Setup <a class="header-anchor" href="#wecom-setup" aria-label="Permalink to &quot;WeCom Setup&quot;">​</a></h2><ol><li>Create an AI app in the <a href="https://work.weixin.qq.com" target="_blank" rel="noreferrer">WeCom Admin Console</a> and obtain the <strong>Bot ID</strong> and <strong>Secret</strong></li><li>In Web UI → <strong>Channels</strong>, create a WeCom channel and fill in Bot ID and Secret</li></ol><h2 id="wechat-setup" tabindex="-1">WeChat Setup <a class="header-anchor" href="#wechat-setup" aria-label="Permalink to &quot;WeChat Setup&quot;">​</a></h2><ol><li>In Web UI → <strong>Channels</strong>, create a WeChat channel</li><li>Click QR login and scan the code with WeChat to authenticate</li><li>Credentials are saved automatically once authenticated</li></ol>',13)])])}const g=t(r,[["render",d]]);export{u as __pageData,g as default};
